15	type Item = { type: string };
16	type Step = { op: string; items: Item[] };
17	type Scenario = { steps: Step[] };
18	
19	const basePremiumForItem = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
20	
21	const sumOfIndividualBasePremiums = (items: Item[]): number =>
22	  items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
23	
24	const countItemsOfType = (items: Item[], type: string): number =>
25	  items.filter((item) => item.type === type).length;
26	
27	const basePremiumFor = (items: Item[]): number => {
28	  if (countItemsOfType(items, "rune") === RUNE_BLOCK_SIZE) return RUNE_BLOCK_PRICE;
29	  return sumOfIndividualBasePremiums(items);
30	};
31	
32	export const runScenario = (input: unknown): { results: Array<{ premium: number }> } => {
33	  const { steps } = input as Scenario;
34	  const premium = basePremiumFor(steps[0].items) + PROCESSING_FEE;
35	  return { results: [{ premium }] };
36	};
