const COMPONENT_TYPES = Object.keys(BASE_PREMIUM_BY_TYPE).filter(
  (type) => BASE_PREMIUM_BY_TYPE[type] === 25,
);

const basePremiumFor = (items: Item[]): number => {
  let total = 0;
  const nonBlockItems: Item[] = [];
  for (const type of COMPONENT_TYPES) {
    if (countItemsOfType(items, type) === RUNE_BLOCK_SIZE) {
      total += RUNE_BLOCK_PRICE;
    } else {
      nonBlockItems.push(...items.filter((item) => item.type === type));
    }
  }
  const otherItems = items.filter((item) => !COMPONENT_TYPES.includes(item.type));
  return total + sumOfIndividualBasePremiums([...nonBlockItems, ...otherItems]);
};
